const inputItems = $input.all();
const outputs = [];

for (const item of inputItems) {
  const body = item.json.body ?? item.json;
  const headers = item.json.headers ?? {};
  const receivedAt = new Date().toISOString();

  const githubEvent = String(headers['x-github-event'] || headers['X-GitHub-Event'] || '').toLowerCase();

  if (body && body.repository && (githubEvent || body.ref || body.action || body.zen)) {
    const owner = body.repository?.owner?.login || body.repository?.owner?.name || '';
    const repo = body.repository?.name || '';

    const eventAction = githubEvent || (body.action ? String(body.action).toLowerCase() : (body.ref ? 'push' : 'repository_event'));
    const allowedEvents = ['push', 'repository_dispatch', 'workflow_dispatch'];
    const ref = String(body.ref || body.repository?.default_branch || '').replace(/^refs\/heads\//, '');

    outputs.push({
      json: {
        skip: !owner || !repo || !allowedEvents.includes(eventAction),
        skip_reason: (!owner || !repo)
          ? 'Repository owner/name missing in webhook payload.'
          : (allowedEvents.includes(eventAction)
              ? ''
              : `Ignoring repository event: ${eventAction || 'unknown'}. Supported: push, repository_dispatch, workflow_dispatch.`),
        trigger_mode: 'automatic',
        event_action: eventAction || 'unknown',
        owner,
        repo,
        ref,
        repo_identifier: owner && repo ? `${owner}/${repo}` : 'unknown',
        received_at: receivedAt,
      },
    });
    continue;
  }

  const repoUrl = body?.repo_url || body?.repository_url || body?.url || body?.repoUrl || body?.repositoryUrl || '';
  const match = typeof repoUrl === 'string'
    ? repoUrl.match(/^https?:\/\/github\.com\/([^\/]+)\/([^\/#?]+)(?:[\/#?].*)?$/i)
    : null;

  if (!match) {
    outputs.push({
      json: {
        skip: true,
        skip_reason: 'Manual mode requires a valid GitHub repository URL in body.repo_url, e.g. https://github.com/owner/repo',
        trigger_mode: 'manual',
        event_action: 'manual_request',
        owner: '',
        repo: '',
        ref: '',
        repo_identifier: 'unknown',
        received_at: receivedAt,
      },
    });
    continue;
  }

  const owner = match[1];
  const repo = match[2].replace(/\.git$/i, '');
  const ref = String(body?.ref || body?.branch || '').replace(/^refs\/heads\//, '');

  outputs.push({
    json: {
      skip: false,
      skip_reason: '',
      trigger_mode: 'manual',
      event_action: 'manual_request',
      owner,
      repo,
      ref,
      repo_identifier: `${owner}/${repo}`,
      received_at: receivedAt,
    },
  });
}

return outputs;

const input = $input.first().json;
const env = (typeof $env !== 'undefined' && $env) ? $env : (process.env || {});
const staticData = $getWorkflowStaticData('global');
if (!staticData.lastReviewedByRepo || typeof staticData.lastReviewedByRepo !== 'object') staticData.lastReviewedByRepo = {};
if (!Array.isArray(staticData.auditLog)) staticData.auditLog = [];

const nowIso = () => new Date().toISOString();
let repoIdentifier = input.repo_identifier || 'unknown';
let commitSha = 'unknown';

const clean = (v) => (typeof v === 'string' ? v.replace(/\s+/g, ' ').trim() : '');
const asList = (arr, maxItems = 8, maxLen = 220) => (Array.isArray(arr) ? arr : [])
  .map(clean)
  .filter(Boolean)
  .slice(0, maxItems)
  .map((v) => (v.length > maxLen ? `${v.slice(0, maxLen - 3)}...` : v));
const ensureRisk = (r) => {
  const x = clean(r).toLowerCase();
  return x === 'low' || x === 'medium' || x === 'high' ? x : 'medium';
};
const addUnique = (arr, value) => {
  const x = clean(value);
  if (!x) return;
  if (!arr.includes(x)) arr.push(x);
};
const audit = (riskLevel, messageLink = '', note = '') => {
  const entry = {
    timestamp: nowIso(),
    repo_identifier: repoIdentifier,
    commit_sha: commitSha,
    risk_level: riskLevel,
    message_link: messageLink || '',
  };
  if (note) entry.note = note;
  staticData.auditLog.unshift(entry);
  staticData.auditLog = staticData.auditLog.slice(0, 500);
  return entry;
};
const wait = async (ms) => new Promise((resolve) => setTimeout(resolve, ms));

const requestWithRetry = async (options, label) => {
  const attempts = Math.max(1, Number(env.HTTP_MAX_ATTEMPTS || 3));
  const baseDelay = Math.max(200, Number(env.HTTP_RETRY_BASE_MS || 1000));

  for (let attempt = 1; attempt <= attempts; attempt++) {
    try {
      if (this?.helpers?.httpRequest) {
        return await this.helpers.httpRequest(options);
      }
      throw new Error('Code node HTTP helper is unavailable in this n8n runtime');
    } catch (e) {
      const status = e?.statusCode || e?.response?.statusCode || e?.response?.status || 0;
      const msg = e?.response?.body?.message || e?.message || 'Unknown request failure';
      const retryable = status === 0 || status === 429 || status >= 500 || status === 403;
      if (!retryable || attempt === attempts) {
        throw new Error(`${label} failed after ${attempt} attempt(s). Status=${status || 'n/a'}. ${msg}`);
      }
      await wait(baseDelay * Math.pow(2, attempt - 1));
    }
  }
};

const encodePath = (p) => String(p).split('/').map((s) => encodeURIComponent(s)).join('/');
const decodeBase64 = (v) => Buffer.from(String(v || '').replace(/\n/g, ''), 'base64').toString('utf8');

try {
  const destination = (clean(env.DESTINATION_MODE) || 'discord').toLowerCase();
  const githubToken = clean(env.GITHUB_TOKEN);
  const openaiKey = clean(env.OPENAI_API_KEY);
  const discordWebhook = clean(env.DISCORD_WEBHOOK_URL);
  const slackWebhook = clean(env.SLACK_WEBHOOK_URL);

  if (!githubToken) throw new Error('Missing required env var GITHUB_TOKEN');
  if (!openaiKey) throw new Error('Missing required env var OPENAI_API_KEY');
  if (destination === 'slack' && !slackWebhook) throw new Error('DESTINATION_MODE=slack but SLACK_WEBHOOK_URL is missing');
  if (destination !== 'slack' && !discordWebhook) throw new Error('DESTINATION_MODE=discord but DISCORD_WEBHOOK_URL is missing');
  if (!input.owner || !input.repo) throw new Error('Normalized payload missing owner/repo');

  repoIdentifier = `${input.owner}/${input.repo}`;
  const timeoutMs = Math.max(1000, Number(env.HTTP_TIMEOUT_MS || 30000));
  const ghHeaders = {
    Authorization: `Bearer ${githubToken}`,
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
    'User-Agent': 'n8n-repo-review-bot',
  };

  const repo = await requestWithRetry({
    method: 'GET',
    url: `https://api.github.com/repos/${input.owner}/${input.repo}`,
    headers: ghHeaders,
    json: true,
    timeout: timeoutMs,
  }, 'Get repository metadata');

  const branchInput = clean(input.ref).replace(/^refs\/heads\//, '');
  const branch = branchInput || clean(repo.default_branch) || 'main';

  const head = await requestWithRetry({
    method: 'GET',
    url: `https://api.github.com/repos/${input.owner}/${input.repo}/commits/${encodeURIComponent(branch)}`,
    headers: ghHeaders,
    json: true,
    timeout: timeoutMs,
  }, 'Get branch head commit');

  commitSha = clean(head?.sha) || 'unknown';
  const dedupeKey = `${repoIdentifier}@${branch}`;
  const isAutomatic = input.trigger_mode === 'automatic';
  if (isAutomatic && staticData.lastReviewedByRepo[dedupeKey] && commitSha !== 'unknown' && staticData.lastReviewedByRepo[dedupeKey] === commitSha) {
    const entry = audit('duplicate_skip', '', 'Same commit already reviewed; skipped to prevent spam.');
    return [{ json: { skipped: true, reason: 'Duplicate commit SHA, skipped.', repo_identifier: repoIdentifier, branch, commit_sha: commitSha, audit_entry: entry } }];
  }

  let languages = {};
  try {
    languages = await requestWithRetry({
      method: 'GET',
      url: `https://api.github.com/repos/${input.owner}/${input.repo}/languages`,
      headers: ghHeaders,
      json: true,
      timeout: timeoutMs,
    }, 'Get repository languages');
  } catch {
    languages = {};
  }

  const treeResp = await requestWithRetry({
    method: 'GET',
    url: `https://api.github.com/repos/${input.owner}/${input.repo}/git/trees/${encodeURIComponent(branch)}?recursive=1`,
    headers: ghHeaders,
    json: true,
    timeout: timeoutMs,
  }, 'Get repository file tree');

  const allBlobs = Array.isArray(treeResp?.tree) ? treeResp.tree.filter((n) => n && n.type === 'blob' && n.path) : [];

  const excludeRe = [/^\.git\//i, /^node_modules\//i, /^dist\//i, /^build\//i, /^coverage\//i, /^vendor\//i, /^\.next\//i, /^out\//i, /^target\//i];
  const isExcluded = (p) => excludeRe.some((re) => re.test(p));
  const allowedExt = ['.md','.txt','.js','.ts','.tsx','.jsx','.py','.java','.go','.rb','.php','.cs','.json','.yml','.yaml','.toml','.ini','.env','.sql','.sh','.ps1','.gradle'];
  const specialNames = ['dockerfile','makefile','readme','license'];
  const hasAllowedType = (p) => {
    const lower = String(p).toLowerCase();
    if (specialNames.some((n) => lower.endsWith(n))) return true;
    return allowedExt.some((ext) => lower.endsWith(ext));
  };

  const priorityPaths = [
    'README.md', 'README', 'package.json', 'package-lock.json', 'pnpm-lock.yaml', 'yarn.lock',
    'pyproject.toml', 'requirements.txt', 'Pipfile', 'go.mod', 'pom.xml', 'build.gradle',
    'Dockerfile', 'docker-compose.yml', 'docker-compose.yaml', '.github/workflows/ci.yml',
    '.github/workflows/main.yml', '.env.example'
  ];

  const blobByPath = new Map();
  for (const b of allBlobs) blobByPath.set(String(b.path), b);

  const selectedPaths = [];
  const addPath = (p) => {
    if (!p || selectedPaths.includes(p) || isExcluded(p)) return;
    selectedPaths.push(p);
  };

  for (const p of priorityPaths) {
    if (blobByPath.has(p)) addPath(p);
  }

  const maxRepoFiles = Math.max(5, Number(env.MAX_REPO_FILES || 20));
  const candidates = allBlobs
    .map((b) => ({ path: String(b.path), size: Number(b.size || 0) }))
    .filter((b) => !isExcluded(b.path) && hasAllowedType(b.path))
    .sort((a, b) => a.path.length - b.path.length || a.size - b.size);

  for (const c of candidates) {
    if (selectedPaths.length >= maxRepoFiles) break;
    addPath(c.path);
  }

  const maxRepoChars = Math.max(4000, Number(env.MAX_REPO_CHARS || 24000));
  const maxFileChars = Math.max(500, Number(env.MAX_REPO_FILE_CHARS || 4000));
  let usedChars = 0;
  const fileSnapshots = [];
  const unavailableFiles = [];
  const truncatedFiles = [];

  for (const path of selectedPaths) {
    if (usedChars >= maxRepoChars) {
      truncatedFiles.push(path);
      continue;
    }

    try {
      const fileData = await requestWithRetry({
        method: 'GET',
        url: `https://api.github.com/repos/${input.owner}/${input.repo}/contents/${encodePath(path)}?ref=${encodeURIComponent(branch)}`,
        headers: ghHeaders,
        json: true,
        timeout: timeoutMs,
      }, `Get file content ${path}`);

      if (!fileData || fileData.type !== 'file' || fileData.encoding !== 'base64' || typeof fileData.content !== 'string') {
        unavailableFiles.push(path);
        continue;
      }

      let text = '';
      try {
        text = decodeBase64(fileData.content);
      } catch {
        unavailableFiles.push(path);
        continue;
      }

      if (!text || /\x00/.test(text)) {
        unavailableFiles.push(path);
        continue;
      }

      const remaining = Math.max(0, maxRepoChars - usedChars);
      const fileBudget = Math.min(maxFileChars, remaining);
      let excerpt = text;
      let coverage = 'full';
      if (text.length > fileBudget) {
        excerpt = text.slice(0, fileBudget);
        coverage = 'truncated';
        truncatedFiles.push(path);
      }

      usedChars += excerpt.length;
      fileSnapshots.push({
        path,
        size: Number(fileData.size || 0),
        excerpt,
        coverage,
      });
    } catch {
      unavailableFiles.push(path);
    }
  }

  let recentCommits = [];
  try {
    recentCommits = await requestWithRetry({
      method: 'GET',
      url: `https://api.github.com/repos/${input.owner}/${input.repo}/commits?sha=${encodeURIComponent(branch)}&per_page=5`,
      headers: ghHeaders,
      json: true,
      timeout: timeoutMs,
    }, 'Get recent commits');
  } catch {
    recentCommits = [];
  }

  const commitSummaries = (Array.isArray(recentCommits) ? recentCommits : []).map((c) => ({
    sha: clean(c?.sha).slice(0, 12),
    author: clean(c?.commit?.author?.name),
    message: clean(c?.commit?.message).split('\n')[0],
  })).filter((x) => x.sha && x.message);

  const secretRegex = /(AKIA[0-9A-Z]{16}|-----BEGIN (?:RSA|EC|DSA|OPENSSH) PRIVATE KEY-----|api[_-]?key\s*[:=]\s*['"][^'"]{8,}|secret\s*[:=]\s*['"][^'"]{8,}|password\s*[:=]\s*['"][^'"]{6,}|xox[baprs]-[A-Za-z0-9-]{10,}|ghp_[A-Za-z0-9]{20,}|AIza[0-9A-Za-z\-_]{35})/i;
  const suspectedSecretExposure = fileSnapshots.some((f) => secretRegex.test(f.excerpt));

  const reviewContext = {
    repository: {
      owner: input.owner,
      repo: input.repo,
      full_name: repo.full_name || repoIdentifier,
      description: repo.description || '',
      default_branch: repo.default_branch || branch,
      branch,
      url: repo.html_url || `https://github.com/${input.owner}/${input.repo}`,
      visibility: repo.private ? 'private' : 'public',
      stars: Number(repo.stargazers_count || 0),
      forks: Number(repo.forks_count || 0),
      open_issues: Number(repo.open_issues_count || 0),
      pushed_at: repo.pushed_at || '',
      topics: Array.isArray(repo.topics) ? repo.topics : [],
      languages,
      head_commit: commitSha,
      recent_commits: commitSummaries,
    },
    files: {
      total_blob_count: allBlobs.length,
      selected_paths: selectedPaths,
      sampled_files: fileSnapshots.map((f) => ({
        path: f.path,
        size: f.size,
        coverage: f.coverage,
        excerpt: f.excerpt,
      })),
      unavailable_files: unavailableFiles,
      truncated_files: truncatedFiles,
      limits: {
        max_repo_files: maxRepoFiles,
        max_repo_chars: maxRepoChars,
        max_file_chars: maxFileChars,
        included_chars: usedChars,
      },
      tree_truncated: Boolean(treeResp?.truncated),
    },
    limitations: {
      sampled_file_count: fileSnapshots.length,
      unavailable_file_count: unavailableFiles.length,
      truncated_file_count: truncatedFiles.length,
      limited_coverage: Boolean(treeResp?.truncated) || unavailableFiles.length > 0 || truncatedFiles.length > 0 || fileSnapshots.length === 0,
    },
    security_signals: {
      suspected_secret_exposure: suspectedSecretExposure,
    },
  };

  const schema = {
    type: 'object',
    additionalProperties: false,
    required: ['summary','risk','risk_reasoning','architecture_observations','code_quality_findings','security_findings','test_coverage_gaps','recommended_next_steps','questions_for_maintainer'],
    properties: {
      summary: { type: 'string' },
      risk: { type: 'string', enum: ['low','medium','high'] },
      risk_reasoning: { type: 'array', items: { type: 'string' } },
      architecture_observations: { type: 'array', items: { type: 'string' } },
      code_quality_findings: { type: 'array', items: { type: 'string' } },
      security_findings: { type: 'array', items: { type: 'string' } },
      test_coverage_gaps: { type: 'array', items: { type: 'string' } },
      recommended_next_steps: { type: 'array', items: { type: 'string' } },
      questions_for_maintainer: { type: 'array', items: { type: 'string' } },
    },
  };

  const aiResp = await requestWithRetry({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      Authorization: `Bearer ${openaiKey}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: clean(env.OPENAI_MODEL) || 'gpt-4.1-mini',
      temperature: 0.1,
      messages: [
        { role: 'system', content: [
          'You are a senior software reviewer producing a repository review packet.',
          'Use ONLY the provided repository metadata, commit summaries, and sampled file excerpts.',
          'Do not hallucinate unseen files or implementation details.',
          'If coverage is limited, explicitly state reduced confidence and what is missing.',
          'Focus on architecture, maintainability, security, and testing gaps.',
          'Return strict JSON with exactly these keys: summary, risk, risk_reasoning, architecture_observations, code_quality_findings, security_findings, test_coverage_gaps, recommended_next_steps, questions_for_maintainer.'
        ].join('\n') },
        { role: 'user', content: `Repository context JSON:\n${JSON.stringify(reviewContext)}` },
      ],
      response_format: {
        type: 'json_schema',
        json_schema: { name: 'repo_review_packet', strict: true, schema },
      },
    },
    json: true,
    timeout: Math.max(2000, Number(env.OPENAI_TIMEOUT_MS || 60000)),
  }, 'Generate repository review packet');

  const content = aiResp?.choices?.[0]?.message?.content;
  let parsed = {};
  if (typeof content === 'string') parsed = JSON.parse(content);
  else if (content && typeof content === 'object') parsed = content;

  const packet = {
    summary: clean(parsed.summary) || 'Automated review could not produce a confident repository summary from available data.',
    risk: ensureRisk(parsed.risk),
    risk_reasoning: asList(parsed.risk_reasoning, 8),
    architecture_observations: asList(parsed.architecture_observations, 8),
    code_quality_findings: asList(parsed.code_quality_findings, 10),
    security_findings: asList(parsed.security_findings, 10),
    test_coverage_gaps: asList(parsed.test_coverage_gaps, 10),
    recommended_next_steps: asList(parsed.recommended_next_steps, 10),
    questions_for_maintainer: asList(parsed.questions_for_maintainer, 8),
  };

  if (reviewContext.limitations.limited_coverage) {
    if (packet.risk === 'low') packet.risk = 'medium';
    addUnique(packet.risk_reasoning, `Review coverage is limited: sampled ${reviewContext.limitations.sampled_file_count} file(s), ${reviewContext.limitations.unavailable_file_count} unavailable, ${reviewContext.limitations.truncated_file_count} truncated.`);
    addUnique(packet.questions_for_maintainer, 'Can you share additional core files/modules for deeper review coverage?');
  }

  if (suspectedSecretExposure) {
    packet.risk = 'high';
    addUnique(packet.security_findings, 'Potential secret/token/private key exposure detected in sampled repository content.');
    addUnique(packet.recommended_next_steps, 'Remove exposed secret material from repository content and configuration files.');
    addUnique(packet.recommended_next_steps, 'Rotate compromised credentials and purge from git history if committed.');
  }

  if (packet.risk === 'high') {
    addUnique(packet.recommended_next_steps, 'Require explicit human security review before production deployment.');
    addUnique(packet.test_coverage_gaps, 'Add regression and security tests for critical code paths before release.');
  }

  const bullet = (arr) => (arr.length ? arr.map((x) => `- ${x}`).join('\n') : '- None.');
  let message = [
    `Repository Review Packet for ${repoIdentifier}`,
    `Branch: ${branch}`,
    `Head: ${commitSha}`,
    '',
    '1) Summary',
    packet.summary,
    '',
    '2) Risk + reasoning',
    `Risk: ${packet.risk.toUpperCase()}`,
    bullet(packet.risk_reasoning),
    '',
    '3) Architecture observations',
    bullet(packet.architecture_observations),
    '',
    '4) Code quality findings',
    bullet(packet.code_quality_findings),
    '',
    '5) Security findings',
    bullet(packet.security_findings),
    '',
    '6) Test coverage gaps',
    bullet(packet.test_coverage_gaps),
    '',
    '7) Recommended next steps',
    bullet(packet.recommended_next_steps),
    '',
    '8) Questions for maintainer',
    bullet(packet.questions_for_maintainer),
  ].join('\n');

  if (packet.risk === 'high') {
    message += '\n\nHigh-Risk Guidance:\n- Human review is strongly required before release.\n- Validate rollback/testing steps before deployment.\n- Do not ship based only on this automated packet.';
  }


  let postResp = {};
  let messageLink = '';

  if (destination === 'slack') {
    postResp = await requestWithRetry({
      method: 'POST',
      url: slackWebhook,
      headers: { 'Content-Type': 'application/json' },
      body: { text: message },
      json: true,
      timeout: timeoutMs,
    }, 'Post Slack message');
  } else {
    const discordUrl = discordWebhook.includes('?') ? `${discordWebhook}&wait=true` : `${discordWebhook}?wait=true`;
    postResp = await requestWithRetry({
      method: 'POST',
      url: discordUrl,
      headers: { 'Content-Type': 'application/json' },
      body: { content: message },
      json: true,
      timeout: timeoutMs,
    }, 'Post Discord message');

    if (postResp?.id && postResp?.channel_id && postResp?.guild_id) {
      messageLink = `https://discord.com/channels/${postResp.guild_id}/${postResp.channel_id}/${postResp.id}`;
    }
  }

  staticData.lastReviewedByRepo[dedupeKey] = commitSha;
  const auditEntry = audit(packet.risk, messageLink);

  return [{
    json: {
      reviewed_at: nowIso(),
      trigger_mode: input.trigger_mode,
      event_action: input.event_action,
      repo_identifier: repoIdentifier,
      branch,
      commit_sha: commitSha,
      review_packet: packet,
      formatted_message: message,
      destination,
      message_link: messageLink,
      audit_entry: auditEntry,
      limitations: reviewContext.limitations,
      post_response_preview: postResp?.ok ?? postResp?.id ?? null,
    },
  }];
} catch (error) {
  audit('error', '', error.message);
  throw new Error(`Repository review workflow failed for ${repoIdentifier}: ${error.message}. Check credentials, rate limits, webhook payload, and repository access.`);
}

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.auditLog)) staticData.auditLog = [];

const entry = {
  timestamp: new Date().toISOString(),
  pr_identifier: item.pr_identifier || 'unknown',
  commit_sha: item.reviewed_sha || 'unknown',
  risk_level: 'ignored_event',
  message_link: '',
  note: item.skip_reason || 'Event ignored before review.',
};

staticData.auditLog.unshift(entry);
staticData.auditLog = staticData.auditLog.slice(0, 500);

return [{ json: { skipped: true, reason: item.skip_reason || 'Event ignored.', audit_entry: entry } }];
